mapper.select:
SELECT COUNT(1)
FROM community_like
WHERE user_id = #{userId}
  AND target_type = 'POST'
  AND target_id = #{postId}

mapper.delete:
DELETE FROM community_like
WHERE user_id = #{userId}
  AND target_type = 'POST'
  AND target_id = #{postId}

mapper.select:
SELECT COUNT(1)
FROM community_author_follow
WHERE user_id = #{userId}
  AND author_id = #{authorId}

SELECT tag FROM ( SELECT trim(regexp_split_to_table(tags, ',')) AS tag, COUNT(*) AS cnt FROM community_post WHERE status = 'PUBLISHED' AND tags IS NOT NULL GROUP BY tag ORDER BY cnt DESC
LIMIT #{limit}
) t WHERE tag IS NOT NULL AND tag != ''
